mapper.select:
SELECT RSK_EVT_SN
  FROM RISK_EVENT
 WHERE RSK_EVT_TYPE_CD = #{typeCode}
   AND RSK_EVT_REF_TYPE_CD <=> #{referenceTypeCode}
   AND RSK_EVT_REF_SN <=> #{referenceSn}
   AND RSK_EVT_CN = #{content}
   AND RSK_EVT_PROC_YN = 'N'
 ORDER BY RSK_EVT_SN DESC
 LIMIT 1

SELECT event.RSK_EVT_SN AS riskEventId, event.RSK_EVT_TYPE_CD AS typeCode, typeCode.CMM_NM AS typeName, event.RSK_EVT_REF_TYPE_CD AS referenceTypeCode, event.RSK_EVT_REF_SN AS referenceSn, event.RSK_EVT_CN AS content, event.RSK_EVT_PROC_YN AS processedYn, event.RSK_EVT_REG_DT AS registeredAt FROM RISK_EVENT event JOIN CMM_CODE typeCode ON typeCode.CMM_CD = event.RSK_EVT_TYPE_CD
event.RSK_EVT_TYPE_CD = #{typeCode}
AND event.RSK_EVT_PROC_YN = #{processedYn}
ORDER BY event.RSK_EVT_REG_DT DESC, event.RSK_EVT_SN DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
  FROM RISK_EVENT event

     event.RSK_EVT_TYPE_CD = #{typeCode}

         AND
         event.RSK_EVT_PROC_YN = #{processedYn}

SELECT event.RSK_EVT_TYPE_CD AS typeCode, typeCode.CMM_NM AS typeName, COUNT(*) AS count FROM RISK_EVENT event JOIN CMM_CODE typeCode ON typeCode.CMM_CD = event.RSK_EVT_TYPE_CD
event.RSK_EVT_PROC_YN = #{processedYn}
GROUP BY event.RSK_EVT_TYPE_CD, typeCode.CMM_NM ORDER BY count DESC, event.RSK_EVT_TYPE_CD ASC
